mapper.update:
update shopping_cart
product_code = #{productCode}, product_title = #{productTitle}, product_sub_title = #{productSubTitle}, product_image = #{productImage}, sku_text = #{skuText}, unit_price = #{unitPrice}, quantity = #{quantity}, is_checked = #{isChecked}, status = #{status}, invalid_reason = #{invalidReason}, update_time = sysdate()
where id = #{id} and user_id = #{userId}

update shopping_cart
set is_checked = #{isChecked},
    update_time = sysdate()
where id = #{id}
  and user_id = #{userId}
  and status = '0'

update shopping_cart
